<!DOCTYPE html>
<html>
<head>
<style>
  body {
    font-family: 'Helvetica Neue', Helvetica, Arial, sans-serif;
    background-color: #f4f7f6;
    margin: 0;
    padding: 0;
    color: #333;
  }
  .container {
    max-width: 640px;
    margin: 30px auto;
    background: #ffffff;
    border-radius: 8px;
    overflow: hidden;
    box-shadow: 0 5px 20px rgba(0,0,0,0.15);
  }
  .header {
    background: linear-gradient(135deg, #1a5c5c 0%, #2d7a7a 100%);
    padding: 32px;
    text-align: center;
    border-top: 5px solid #b88a4d;
  }
  .header h1 {
    color: #b88a4d;
    margin: 0 0 4px 0;
    font-size: 26px;
    letter-spacing: 1px;
    font-family: 'Georgia', serif;
    text-transform: uppercase;
    text-shadow: 1px 1px 2px rgba(0,0,0,0.3);
  }
  .header p {
    color: #c8e6e6;
    margin: 0;
    font-size: 12px;
    letter-spacing: 2px;
    text-transform: uppercase;
  }

  .content {
    padding: 32px 36px 40px 36px;
    font-size: 15px;
    line-height: 1.9;
    color: #444;
  }

  .meta {
    font-size: 13px;
    color: #666;
    margin-bottom: 18px;
  }

  h2 {
    color: #1a5c5c;
    font-size: 20px;
    margin: 0 0 10px 0;
  }
  h3 {
    color: #1a5c5c;
    font-size: 17px;
    margin: 26px 0 8px 0;
  }
  ol {
    padding-left: 18px;
    margin: 14px 0 6px 0;
  }
  ol li {
    margin-bottom: 14px;
  }

  .bonus {
    margin-top: 26px;
  }
  .bonus-label {
    font-size: 14px;
    font-weight: 600;
    color: #1a5c5c;
    margin-bottom: 8px;
  }
  .caption-box {
    background: #f0f3f4;
    border-radius: 6px;
    padding: 14px 16px;
    font-size: 14px;
    line-height: 1.7;
  }

  .btn-box {
    text-align: center;
    margin-top: 32px;
  }
  .btn-approve {
    display: inline-block;
    background: linear-gradient(135deg, #1a5c5c 0%, #2d7a7a 100%);
    color: #1a5c5c;
    padding: 14px 40px;
    text-decoration: none;
    border-radius: 4px;
    font-weight: bold;
    font-size: 15px;
    letter-spacing: 1px;
    border-bottom: 4px solid #b88a4d;
    box-shadow: 0 4px 6px rgba(0,0,0,0.2);
  }

  .footer {
    background: linear-gradient(135deg, #1a5c5c 0%, #2d7a7a 100%);
    text-align: center;
    padding: 20px 10px;
    font-size: 12px;
    color: #c8e6e6;
    border-bottom: 5px solid #b88a4d;
  }
  .footer span {
    color: #b88a4d;
  }
</style>
</head>
<body>

<div class="container">
  <div class="header">
    <h1>GREENLINE 365</h1>
    <p>GLOBAL SUSTAINABLE SOLUTIONS</p>
  </div>

  <div class="content">
    ${ $('AI Summary Agent').item.json.output || $('AI Summary Agent').item.json.text || "⚠️ Waiting for AI Content..." }

    <div class="btn-box">
      <a href="#" class="btn-approve">APPROVE POST</a>
    </div>
  </div>

  <div class="footer">
    <p>Powered by <span>GreenLine365</span> | Local Business Intelligence</p>
  </div>
</div>

</body>
</html>
`

